INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-57f41407-moex-00196', 'disabled-57f41407', 'disabled-57f41407-moex-113-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「聯合國在2022年發布的2023人口報告中就警告，所有國家都需要為人 口老化的現實做好準備。因為社會與經濟的衰老與停滯是大多數富裕國家 與中等收入國家被迫面對的共同難題。生存狀況顯著改善與生育率下降， 已經讓人口老化成為這個時代不可逆轉的全球趨勢，越晚面對人口老化問 題，所要負擔的社會、經濟、財政和衛生成本將越高昂。」 根據上文，關於人口老化的原因，下列推論何者正確？', '["富裕與中等收入國家的政策是造成人口老化的原因", "經濟不斷衰退，造成人口老化，這是目前全球所面臨的難題", "因為衛生成本逐年增加，導致經濟停滯，間接影響國家的生存狀況", "生育率下降與生存狀況的改善，讓人口老化成為全球共同面臨的問題"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:35+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00197', 'disabled-57f41407', 'disabled-57f41407-moex-113-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「臺灣森林分為天然林與人工林，目前天然林因保育而全面禁伐，但人工 林則否。在世界提倡淨碳排的趨勢下，森林『碳匯』議題越來越被重視—— 意即森林具有固碳功能，可以將二氧化碳吸存固著於自然環境中，形成如 同把錢存在銀行一樣的倉庫。因此，要增加碳匯，就必須多造林。然而， 樹木會老化，過了 20 年的生長巔峰期，固碳能力逐年下降，最後失去固 碳功能，是以人工林的更新有其必要性。」 根據上文，下列選項最符合文意的是：', '["樹齡越大、枝葉越茂盛，對環境保護的效益越大", "人工林的造林和定期採伐，有其實質上的必要性", "環境意識的崛起，禁伐已是全球山林保育的趨勢", "天然林比人工林更具有碳匯的效益，可增加獲利"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:35+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00198', 'disabled-57f41407', 'disabled-57f41407-moex-113-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '某企業代表在產業高峰會中表示：「為了能招募外國人才，加上臺灣環境 資源有限，包括土地、水、電，走出臺灣是不得不做的事情。然而在海外 布局的過程面臨兩個挑戰，首先是全球人才不足，不僅人口變少，念半導 體的人也變少。另一個挑戰是文化融合，應以開放心態因應。全球化布局 可能造成成本增加，增加的成本是由客戶吸收，或企業自行吸收，將會是 挑戰，也是企業全球化要面對的議題。」 根據上文，下列選項何者正確？', '["產業發展必須倚賴全球人才，但也要考慮文化融合的衝擊", "受新冠肺炎疫情影響，人才流動受限，因此必須走出臺灣", "為了產品標準化，應該統一各地製程、管理、營運之步驟", "全球布局能利用各地廉價的勞工、土地、水電，降低成本"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:35+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00199', 'disabled-57f41407', 'disabled-57f41407-moex-113-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「一葉知秋，一根頭髮可以讓罪犯無所遁形。可見，頭髮就是人這棵樹的 葉子。秋天到了，葉轉黃，年紀大了，髮變白。人與時間拔河，以白髮為 繩。老，本是自然律裡的事，擋不了也無須擋。一派天真自然，反而能使 『老』這件事顯出美好的部分。我不討厭白髮，有時還覺得有些人的白髮 長得真好看。如果一棵樹的葉子綠得像幫派，看久了會膩，若泛起霜紅色 澤，美就來了。人亦如此，渾身上下要一起老才好。白髮是落雪天氣，人 生走到這一步，離暴動份子的時代遠了，較接近沉思的智者。」 根據上文，下列選項何者最符合文意？', '["活到老，學到老", "老吾老，以及人之老", "夕陽無限好，正是近黃昏", "人間只道黃金貴，不問天公買少年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:35+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00200', 'disabled-57f41407', 'disabled-57f41407-moex-113-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「人天生就有建築的本能。《高塔，一種□□□□的建築》一書中，描述 一個事業受挫、婚姻失敗的中年人，自己到野外湖濱建造高塔的過程。雖 然不是建築科班出身，但他受到內心本能的驅使，開始在湖邊建造一座高 塔。過程中，他感受到內心的沉澱與改變。等到高塔建造完成，他似乎得 到了某種力量，又可以重新去面對自己不完美的人生。」 根據文意，最適合填入□□□□，用以描述文中高塔特質的選項是：', '["隨心所欲", "自我療癒", "挑戰極限", "睥睨天下"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:35+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00201', 'disabled-57f41407', 'disabled-57f41407-moex-113-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '甲（住所在苗栗縣）欲以乙（住所在新竹市）為被告，起訴請求侵權行為 損害賠償，侵權行為地為桃園市。甲得在下列何法院合法起訴？', '["在臺灣新竹地方法院或臺灣苗栗地方法院", "在臺灣桃園地方法院或臺灣新竹地方法院", "在臺灣桃園地方法院或臺灣苗栗地方法院", "只得在臺灣桃園地方法院"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:35+00:00", "source_pdf_sha1": "391f7c61502f", "answer_pdf_sha1": "032ff59ad495", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "505", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00202', 'disabled-57f41407', 'disabled-57f41407-moex-113-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '甲主張其所有坐落臺北市之房地（下稱系爭房地）委託乙（住所地為高雄 市）管理，並將所有權狀交予乙，嗣經伊終止該委託契約，乙拒不返還系 爭房地所有權狀，爰依所有物返還請求權，向臺灣高雄地方法院（下稱高 雄地院）起訴請求乙返還系爭房地所有權狀。高雄地院以本件訴訟應由臺 灣臺北地方法院（下稱臺北地院）管轄為由，依職權裁定移送臺北地院。 甲對該裁定不服，提起抗告。下列何者正確？', '["本件因不動產之物權涉訟，應由不動產所在地之法院即臺北地院管轄", "本件因與不動產有關之事項涉訟，應由不動產所在地之法院即臺北地院 管轄", "本件因與不動產有關之事項涉訟，得由不動產所在地之法院即臺北地院 管轄，高雄地院將本件訴訟依職權移轉管轄，並無違誤", "抗告法院如以高雄地院對本件訴訟有管轄權為由，廢棄原裁定。對於抗 告法院之裁定，當事人不得聲明不服"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:35+00:00", "source_pdf_sha1": "391f7c61502f", "answer_pdf_sha1": "032ff59ad495", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "505", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00203', 'disabled-57f41407', 'disabled-57f41407-moex-113-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '下列何者，非法官應自行迴避的情形？', '["法官曾參與該訴訟事件之更審前的裁判", "法官曾為該訴訟事件當事人的家屬", "法官於該訴訟事件曾為證人", "法官的未婚夫為該訴訟事件當事人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:35+00:00", "source_pdf_sha1": "391f7c61502f", "answer_pdf_sha1": "032ff59ad495", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "505", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00204', 'disabled-57f41407', 'disabled-57f41407-moex-113-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於訴訟告知，下列何者錯誤？', '["訴訟繫屬中，當事人得將訴訟告知因自己敗訴而有法律上利害關係之第 三人", "告知訴訟，應以書狀提出於法院，由法院送達於應受告知之第三人", "受告知人不為參加或參加逾時者，視為於得行參加時已參加於訴訟", "受告知訴訟而參加訴訟者，不得代其所輔助之當事人承當訴訟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:35+00:00", "source_pdf_sha1": "391f7c61502f", "answer_pdf_sha1": "032ff59ad495", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "505", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00205', 'disabled-57f41407', 'disabled-57f41407-moex-113-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於訴訟費用負擔，下列何者錯誤？', '["各當事人一部勝訴、一部敗訴者，法院得命兩造各自負擔其支出之訴訟 費用", "因共有物分割事件涉訟，法院均應命敗訴之當事人負擔訴訟費用", "敗訴人之行為，按當時之訴訟程度，為伸張或防衛權利所必要者，法院 得命勝訴之當事人負擔全部或一部該行為所生之費用", "被告對原告關於訴訟標的之主張逕行認諾，並能證明其無庸起訴者，訴 訟費用由原告負擔"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:35+00:00", "source_pdf_sha1": "391f7c61502f", "answer_pdf_sha1": "032ff59ad495", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "505", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL)
